    fn discover_configs_empty_when_no_shatter_dirs() {
        let dir = TempDir::new().unwrap();
        let sub = dir.path().join("some").join("path");
        fs::create_dir_all(&sub).unwrap();

        let configs = discover_configs(&sub).unwrap();
        assert!(configs.is_empty());
    }

