                timeout: None,
                ..DefaultsConfig::default()
            },
            functions: HashMap::new(),
            ..ShatterConfig::default()
        };
        let far = ShatterConfig {
            defaults: DefaultsConfig {
                max_iterations: Some(50),
                timeout: Some(120),
                ..DefaultsConfig::default()
