    /// Build a minimal ExecuteResult with specified branch decisions and lines.
    fn make_exec_result(
        branch_ids: &[(u32, bool)],
        lines: &[u32],
    ) -> ExecuteResult {
        ExecuteResult {
            return_value: Some(serde_json::json!(42)),
            thrown_error: None,
            branch_path: branch_ids
                .iter()
                .map(|&(id, taken)| BranchDecision {
                    branch_id: id,
                    line: id * 10,
                    taken,
