    /// Generate a random BranchDecision with a given branch_id.
    fn arb_branch_decision(max_id: u32) -> impl Strategy<Value = BranchDecision> {
        (0..max_id, any::<bool>()).prop_map(|(id, taken)| BranchDecision {
