pub fn arb_command() -> impl Strategy<Value = Command> {
    prop_oneof![
        prop::collection::vec(arb_ident(), 0..=3)
            .prop_map(|capabilities| Command::Handshake { capabilities }),
        (arb_ident(), proptest::option::of(arb_ident())).prop_map(|(file, function)| {
            Command::Analyze {
                file,
                function,
                project_root: None,
            }
        }),
        (
            arb_ident(),
            arb_ident(),
            prop::collection::vec(arb_mock_config(), 0..=2),
        )
            .prop_map(|(file, function, mocks)| Command::Instrument {
                file,
                function,
                mocks,
                project_root: None,
            }),
        (
            arb_ident(),
            prop::collection::vec(arb_json_value(), 0..=4),
            prop::collection::vec(arb_mock_config(), 0..=2),
        )
            .prop_map(|(function, inputs, mocks)| Command::Execute {
                function,
                inputs,
                mocks,
                setup_context: None,
            }),
        (arb_ident(), arb_ident(), arb_setup_mode()).prop_map(|(file, function, mode)| {
            Command::Setup {
                file,
                function,
                mode,
                project_root: None,
            }
        }),
        arb_ident().prop_map(|function| Command::Teardown { function }),
        (arb_ident(), arb_ident(), arb_generator_kind()).prop_map(|(file, name, kind)| {
            Command::Generate {
                file,
                name,
                kind,
                recipe: None,
                project_root: None,
            }
        }),
        Just(Command::Shutdown),
