        .prop_map(|(invariant, target, label, conf_pct, total_count)| {
            let confidence = f64::from(conf_pct) / 100.0;
            let satisfied_count = ((confidence * total_count as f64).round() as usize).min(total_count);
            ClassifiedInvariant {
                invariant,
                target,
                label,
                confidence,
                satisfied_count,
                total_count,
            }
        })
