pub fn arb_error_info() -> impl Strategy<Value = ErrorInfo> {
    (
        arb_ident(),
        arb_short_string(),
        proptest::option::of(arb_short_string()),
        proptest::option::of(prop_oneof![
            Just("validation".to_string()),
            Just("runtime".to_string()),
            Just("infrastructure".to_string()),
